def validate_label(label: str) -> bool:
    """Validate a label against allowlist and format rules."""
    if not label or not isinstance(label, str):
        return False
    if len(label) > MAX_LABEL_LENGTH:
        return False
    if not ALLOWED_LABEL_PATTERN.match(label):
        return False
    allowed = get_allowed_labels()
    if allowed and label not in allowed:
        return False
    return True


def validate_image_id(image_id: str) -> bool:
    """Validate image ID format."""
    if not image_id or not isinstance(image_id, str):
        return False
    if len(image_id) > MAX_IMAGE_ID_LENGTH:
        return False
    if not ALLOWED_IMAGE_ID_PATTERN.match(image_id):
        return False
    return True


def generate_token(annotator_id: int, role: str) -> str:
    """Generate a JWT token for an authenticated annotator."""
    payload = {
        'annotator_id': annotator_id,
        'role': role,
        'exp': datetime.utcnow() + timedelta(hours=TOKEN_EXPIRY_HOURS),
        'iat': datetime.utcnow(),
        'jti': secrets.token_hex(16)
    }
    return jwt.encode(payload, JWT_SECRET, algorithm='HS256')


def verify_token(token: str) -> Optional[dict]:
    """Verify and decode a JWT token."""
    try:
        payload = jwt.decode(token, JWT_SECRET, algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        logger.info("Expired token presented")
        return None
    except jwt.InvalidTokenError:
        logger.warning("Invalid token presented")
        return None


def require_auth(f):
    """Authentication decorator."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid authorization header'}), 401

        token = auth_header[7:]
        payload = verify_token(token)
        if not payload:
            return jsonify({'error': 'Invalid or expired token'}), 401

        g.annotator_id = payload['annotator_id']
        g.role = payload['role']
        return f(*args, **kwargs)
    return decorated


def require_admin(f):
    """Admin authorization decorator."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if g.get('role') != 'admin':
            logger.warning(f"Unauthorized admin access attempt by annotator {g.get('annotator_id')}")
            audit_log(g.get('annotator_id'), 'unauthorized_admin_access', 'Attempted admin action')
            return jsonify({'error': 'Insufficient permissions'}), 403
        return f(*args, **kwargs)
    return decorated


def check_rate_limit(annotator_id: int) -> bool:
    """Check if annotator has exceeded rate limit."""
    db = get_db()
    window_start = datetime.utcnow().replace(second=0, microsecond=0)

    row = db.execute(
        'SELECT request_count FROM rate_limits WHERE annotator_id = ? AND window_start = ?',
        (annotator_id, window_start)
    ).fetchone()

    if row and row['request_count'] >= MAX_LABELS_PER_MINUTE:
        return False

    if row:
        db.execute(
            'UPDATE rate_limits SET request_count = request_count + 1 WHERE annotator_id = ? AND window_start = ?',
            (annotator_id, window_start)
        )
    else:
        db.execute(
            'INSERT INTO rate_limits (annotator_id, window_start, request_count) VALUES (?, ?, 1)',
            (annotator_id, window_start)
        )

    # Clean up old rate limit entries
    cutoff = datetime.utcnow() - timedelta(minutes=5)
    db.execute('DELETE FROM rate_limits WHERE window_start < ?', (cutoff,))
    db.commit()
    return True


