def check_annotator_trust(annotator_id: int) -> bool:
    """Check if an annotator is still trusted based on agreement rate."""
    db = get_db()
    row = db.execute(
        'SELECT is_trusted, total_annotations, agreement_count FROM annotators WHERE id = ?',
        (annotator_id,)
    ).fetchone()

    if not row:
        return False

    if not row['is_trusted']:
        return False

    # Need minimum annotations before evaluating trust
    if row['total_annotations'] >= 10:
        agreement_rate = row['agreement_count'] / row['total_annotations']
        if agreement_rate < ANNOTATOR_TRUST_THRESHOLD:
            # Mark annotator as untrusted - potential label flipper
            db.execute('UPDATE annotators SET is_trusted = 0 WHERE id = ?', (annotator_id,))
            # Invalidate their annotations
            db.execute('UPDATE annotations SET is_valid = 0 WHERE annotator_id = ?', (annotator_id,))
            db.commit()
            logger.warning(f"Annotator {annotator_id} marked untrusted (agreement rate: {agreement_rate:.2f})")
            audit_log(annotator_id, 'trust_revoked', f'Agreement rate: {agreement_rate:.2f}')
            return False

    return True


def compute_majority_vote(image_id: str) -> Optional[dict]:
    """Compute majority vote for an image, weighted by annotator trust."""
    db = get_db()

    # Only use valid annotations from trusted annotators
    annotations = db.execute('''
        SELECT a.label, a.confidence, an.agreement_count, an.total_annotations
        FROM annotations a
        JOIN annotators an ON a.annotator_id = an.id
        WHERE a.image_id = ? AND a.is_valid = 1 AND an.is_trusted = 1
    ''', (image_id,)).fetchall()

    if len(annotations) < MIN_ANNOTATIONS_FOR_CONSENSUS:
        return None

    # Weighted majority voting based on annotator reliability
    weighted_votes = Counter()
    for ann in annotations:
        total = ann['total_annotations']
        if total > 0:
            weight = (ann['agreement_count'] / total) * ann['confidence']
        else:
            weight = ann['confidence'] * 0.5  # Lower weight for new annotators
        weighted_votes[ann['label']] += weight

    if not weighted_votes:
        return None

    winner_label = weighted_votes.most_common(1)[0][0]
    total_weight = sum(weighted_votes.values())
    winner_weight = weighted_votes[winner_label]
    agreement_ratio = winner_weight / total_weight if total_weight > 0 else 0

    return {
        'label': winner_label,
        'vote_count': sum(1 for a in annotations if a['label'] == winner_label),
        'total_votes': len(annotations),
        'agreement_ratio': round(agreement_ratio, 4)
    }


def update_annotator_trust_scores():
    """Update trust scores for all annotators based on consensus."""
    db = get_db()

    # Get all consensus labels
    consensus = db.execute('SELECT image_id, label FROM consensus_labels').fetchall()
    consensus_map = {row['image_id']: row['label'] for row in consensus}

    if not consensus_map:
        return

    # Get all annotators
    annotators = db.execute('SELECT id FROM annotators WHERE is_trusted = 1').fetchall()

    for annotator in annotators:
        aid = annotator['id']
        annotations = db.execute(
            'SELECT image_id, label FROM annotations WHERE annotator_id = ? AND is_valid = 1',
            (aid,)
        ).fetchall()

        total = 0
        agreements = 0
        for ann in annotations:
            if ann['image_id'] in consensus_map:
                total += 1
                if ann['label'] == consensus_map[ann['image_id']]:
                    agreements += 1

        if total > 0:
            db.execute(
                'UPDATE annotators SET total_annotations = ?, agreement_count = ? WHERE id = ?',
                (total, agreements, aid)
            )

    db.commit()


