@app.route('/api/register', methods=['POST'])
def register():
    """Register a new annotator."""
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid JSON'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    # Validate username
    if not username or len(username) < 3 or len(username) > 50:
        return jsonify({'error': 'Username must be 3-50 characters'}), 400
    if not re.match(r'^[a-zA-Z0-9_]+$', username):
        return jsonify({'error': 'Username must be alphanumeric with underscores only'}), 400

    # Validate password strength
    if len(password) < 12:
        return jsonify({'error': 'Password must be at least 12 characters'}), 400
    if not re.search(r'[A-Z]', password) or not re.search(r'[a-z]', password) or not re.search(r'[0-9]', password):
        return jsonify({'error': 'Password must contain uppercase, lowercase, and digits'}), 400

    db = get_db()
    try:
        password_hash = generate_password_hash(password, method='pbkdf2:sha256:260000')
        db.execute(
            'INSERT INTO annotators (username, password_hash, role) VALUES (?, ?, ?)',
            (username, password_hash, 'annotator')
        )
        db.commit()
        audit_log(None, 'register', f'New annotator registered: {username}')
        logger.info(f"New annotator registered: {username}")
        return jsonify({'message': 'Registration successful'}), 201
    except sqlite3.IntegrityError:
        return jsonify({'error': 'Username already exists'}), 409


@app.route('/api/login', methods=['POST'])
def login():
    """Authenticate and get a JWT token."""
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid JSON'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400

    db = get_db()
    user = db.execute(
        'SELECT id, password_hash, role, is_trusted FROM annotators WHERE username = ?',
        (username,)
    ).fetchone()

    if not user or not check_password_hash(user['password_hash'], password):
        # Constant-time comparison already done by check_password_hash
        logger.info(f"Failed login attempt for username: {username}")
        audit_log(None, 'failed_login', f'Username: {username}')
        # Use generic error message to prevent user enumeration
        return jsonify({'error': 'Invalid credentials'}), 401

    if not user['is_trusted']:
        audit_log(user['id'], 'login_blocked', 'Untrusted annotator attempted login')
        return jsonify({'error': 'Account suspended'}), 403

    token = generate_token(user['id'], user['role'])

    # Update last active
    db.execute('UPDATE annotators SET last_active = CURRENT_TIMESTAMP WHERE id = ?', (user['id'],))
    db.commit()

    audit_log(user['id'], 'login', 'Successful login')
    return jsonify({'token': token, 'role': user['role']}), 200


@app.route('/api/labels', methods=['POST'])
@require_auth
def submit_label():
    """Submit a label for an image."""
    annotator_id = g.annotator_id

    # Check rate limit
    if not check_rate_limit(annotator_id):
        audit_log(annotator_id, 'rate_limited', 'Exceeded label submission rate')
        return jsonify({'error': 'Rate limit exceeded. Try again later.'}), 429

    # Check annotator trust
    if not check_annotator_trust(annotator_id):
        return jsonify({'error': 'Account suspended due to quality concerns'}), 403

    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid JSON'}), 400

    image_id = data.get('image_id', '').strip()
    label = data.get('label', '').strip()
    confidence = data.get('confidence', 1.0)

    # Validate inputs
    if not validate_image_id(image_id):
        return jsonify({'error': 'Invalid image ID format'}), 400

    if not validate_label(label):
        allowed = get_allowed_labels()
        if allowed:
            return jsonify({'error': f'Invalid label. Allowed labels: {sorted(allowed)}'}), 400
        return jsonify({'error': 'Invalid label format'}), 400

    # Validate confidence
    try:
        confidence = float(confidence)
        if not (0.0 <= confidence <= 1.0):
            return jsonify({'error': 'Confidence must be between 0 and 1'}), 400
    except (TypeError, ValueError):
        return jsonify({'error': 'Invalid confidence value'}), 400

    db = get_db()

    # Check max annotations per image
    count = db.execute(
        'SELECT COUNT(*) as cnt FROM annotations WHERE image_id = ? AND is_valid = 1',
        (image_id,)
    ).fetchone()['cnt']

    if count >= MAX_ANNOTATIONS_PER_IMAGE:
        return jsonify({'error': 'Maximum annotations reached for this image'}), 409

    try:
        db.execute(
            'INSERT INTO annotations (image_id, annotator_id, label, confidence) VALUES (?, ?, ?, ?)',
            (image_id, annotator_id, label, confidence)
        )
        db.commit()
    except sqlite3.IntegrityError:
        return jsonify({'error': 'You have already labeled this image'}), 409

    # Try to compute consensus
    consensus = compute_majority_vote(image_id)
    if consensus:
        db.execute('''
            INSERT OR REPLACE INTO consensus_labels (image_id, label, vote_count, total_votes, agreement_ratio, updated_at)
            VALUES (?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
        ''', (image_id, consensus['label'], consensus['vote_count'],
              consensus['total_votes'], consensus['agreement_ratio']))
        db.commit()

        # Periodically update trust scores
        total_consensus = db.execute('SELECT COUNT(*) as cnt FROM consensus_labels').fetchone()['cnt']
        if total_consensus % 10 == 0:
            update_annotator_trust_scores()

    audit_log(annotator_id, 'submit_label', f'image: {image_id}')
    logger.info(f"Label submitted for image {image_id} by annotator {annotator_id}")

    return jsonify({
        'message': 'Label submitted successfully',
        'consensus': consensus
    }), 201


