@app.route('/api/train', methods=['POST'])
@require_auth
@require_admin
def train_model():
    """Train a model on consensus-labeled data."""
    db = get_db()

    data = request.get_json(silent=True) or {}
    min_agreement = data.get('min_agreement', 0.7)

    try:
        min_agreement = float(min_agreement)
        if not (0.0 <= min_agreement <= 1.0):
            return jsonify({'error': 'min_agreement must be between 0 and 1'}), 400
    except (TypeError, ValueError):
        return jsonify({'error': 'Invalid min_agreement value'}), 400

    # Get high-confidence consensus labels
    consensus_data = db.execute(
        'SELECT image_id, label FROM consensus_labels WHERE agreement_ratio >= ?',
        (min_agreement,)
    ).fetchall()

    if len(consensus_data) < 10:
        return jsonify({'error': 'Insufficient labeled data for training (minimum 10 samples)'}), 400

    image_ids = [row['image_id'] for row in consensus_data]
    labels = [row['label'] for row in consensus_data]

    # Check we have at least 2 classes
    unique_labels = set(labels)
    if len(unique_labels) < 2:
        return jsonify({'error': 'Need at least 2 label classes for training'}), 400

    # Encode labels
    label_encoder = LabelEncoder()
    encoded_labels = label_encoder.fit_transform(labels)

    # Generate feature vectors from image IDs (placeholder - in production, load actual image features)
    # Using deterministic hash-based features for reproducibility
    features = []
    for img_id in image_ids:
        # In production, this would load pre-extracted image features
        hash_bytes = hashlib.sha256(img_id.encode('utf-8')).digest()
        feature_vector = np.frombuffer(hash_bytes, dtype=np.uint8).astype(np.float64) / 255.0
        features.append(feature_vector)

    X = np.array(features)
    y = encoded_labels

    # Train model
    try:
        model = LogisticRegression(
            max_iter=1000,
            C=1.0,
            solver='lbfgs',
            multi_class='multinomial'
        )
        model.fit(X, y)

        # Calculate training accuracy
        train_accuracy = model.score(X, y)

        audit_log(g.annotator_id, 'train_model',
                  f'Samples: {len(X)}, Classes: {len(unique_labels)}, Train acc: {train_accuracy:.4f}')

        logger.info(f"Model trained: {len(X)} samples, {len(unique_labels)} classes, accuracy: {train_accuracy:.4f}")

        return jsonify({
            'message': 'Model trained successfully',
            'training_samples': len(X),
            'num_classes': len(unique_labels),
            'classes': sorted(list(unique_labels)),
            'training_accuracy': round(train_accuracy, 4),
            'min_agreement_threshold': min_agreement
        }), 200

    except Exception as e:
        logger.error(f"Training failed: {type(e).__name__}")
        return jsonify({'error': 'Model training failed'}), 500


